			", data: ", data
		).postln;
	}}
	{ type == "songPosition" } {{
		arg position, srcID;
		~sources[srcID].catArgs(
			", ", (type ++ ",").padRight(12),
			", position: ", position
		).postln;
	}}
	{ type == "songSelect" } {{
		arg song, srcID;
		~sources[srcID].catArgs(
			", ", (type ++ ",").padRight(12),
			", song: ", song
		).postln;
	}}
	{ [
		"tuneRequest",
		"midiClock",
		"tick",
		"start",
		"stop",
		"continue"
		"reset",
		"activeSense"
	].includesEqual(type) } {{
		arg srcID;
		~sources[srcID].catArgs(
			", ", (type ++ ",").padRight(12)
		).postln;
	}}
	{ type == "sysrt" } {{
		arg data, srcID, index;
		var table;
		table = Dictionary.newFrom([
			1, "MIDI Time Code Quarter Frames",
			2, "Song Position",
			3, "Song Select",
			6, "Tune Request",
			8, "MIDI Clock",
			9, "Tick",
			10, "Start",
			11, "Continue",
			12, "Stop",
			14, "Active Sense",
			15, "Reset"
		]);

		~sources[srcID].catArgs(
			", ", (type ++ ",").padRight(12),
			", ", table[index]
		).postln;
	}}
	{ true } {{ arg ...args; args.postln }};

	MIDIdef.new(key, func, nil, nil, msgType);
})
